// Solution
const express = require('express');
const app = express();
app.get('/users/:userId', (req, res) => {
  const userId = req.params.userId;
  if (!isNaN(userId) && parseInt(userId) > 0) {
    res.send(userId);
  } else {
    res.status(400).send('Invalid user ID');
  }
});
app.listen(3000, () => {
  console.log('Server started on port 3000');
});

